import android.util.Log;
import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.Response;

import java.io.IOException;

public class DebugLoggingInterceptor implements Interceptor {
    private static final String TAG = "NetworkDebugLogger";

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request request = chain.request();
        long startTime = System.nanoTime();

        Log.d(TAG, String.format("Starting request %s on %s%n%s",
                request.url(), chain.connection(), request.headers()));

        if (request.body() != null) {
            Log.i(TAG, "Request body: " + request.body().toString());
        }

        Response response = chain.proceed(request);
        long endTime = System.nanoTime();

        Log.d(TAG, String.format("Received response for %s in %.1fms%n%s",
                response.request().url(), (endTime - startTime) / 1e6d, response.headers()));

        if (!response.isSuccessful()) {
            Log.e(TAG, "Request failed: " + response.code());
        }

        if (response.body() != null) {
            Log.i(TAG, "Response body: " + response.body().string());
        }

        return response;
    }
}